-- Elite BBS Rims - Product Seed SQL
-- Premium Aftermarket Wheels for Performance Enthusiasts
-- First 50 products: Konig, BBS, Raceline
-- Run: mysql -u root -h 127.0.0.1 -P 3306 elitebbs_db < product_seed.sql

USE elitebbs_db;
SET NAMES utf8mb4;

CREATE TABLE IF NOT EXISTS products (
    id                INT PRIMARY KEY AUTO_INCREMENT,
    name              VARCHAR(255)  NOT NULL,
    slug              VARCHAR(255)  UNIQUE NOT NULL,
    description       TEXT,
    short_description VARCHAR(500),
    price             DECIMAL(10,2) NOT NULL,
    sale_price        DECIMAL(10,2) DEFAULT NULL,
    sku               VARCHAR(100)  UNIQUE,
    stock             INT           DEFAULT 10,
    category          VARCHAR(100),
    brand             VARCHAR(100),
    size              VARCHAR(50),
    finish            VARCHAR(50),
    fitment_data      TEXT,
    images            JSON,
    featured          BOOLEAN       DEFAULT FALSE,
    status            ENUM('active','draft') DEFAULT 'active',
    created_at        TIMESTAMP     DEFAULT CURRENT_TIMESTAMP,
    updated_at        TIMESTAMP     DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    INDEX idx_status   (status),
    INDEX idx_category (category),
    INDEX idx_slug     (slug)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

SET FOREIGN_KEY_CHECKS = 0;
TRUNCATE TABLE products;
SET FOREIGN_KEY_CHECKS = 1;

INSERT INTO products
    (name, slug, description, short_description, price, sale_price, sku, stock, category, brand, size, finish, fitment_data, images, featured, status)
